    def union(x: Int, y: Int): Unit = {
        val rx = find(x)
        val ry = find(y)
        if (rx != ry) {
            if (rank(rx) < rank(ry)) {
                parent(rx) = ry
            } else if (rank(rx) > rank(ry)) {
                parent(ry) = rx
            } else {
                parent(ry) = rx
                rank(rx) += 1
            }
            compCount -= 1
        }
    }

    def count: Int = compCount
