    val maxT = if (edges.isEmpty) 0L else edges.map(_(2)).max
    var low: Long = 0
    var high: Long = maxT + 1

    class DSU(val n: Int) {
        private val parent = (0 until n).toArray
        private val rank = Array.fill(n)(0)
        private var compCount = n

        def getCount: Int = compCount

        def find(x: Int): Int = {
            var root = x
            while (parent(root) != root) {
                root = parent(root)
            }
            var cur = x
            while (cur != root) {
                val next = parent(cur)
                parent(cur) = root
                cur = next
            }
            root
